"""
detection losses
"""
import torch
import torch.nn as nn
import torch.nn.functional as F


def reduce(loss, mode='none'):
    """
    reduce mode

    Args:
        loss: multidim loss
        mode: either "mean", "sum" or "none"
    Returns:
        reduced loss
    """
    if mode == 'mean':
        loss = loss.mean()
    elif mode == 'sum':
        loss = loss.sum()
    return loss


def softmax_focal_loss(pred, target, reduction='none'):
    """Softmax focal loss

    Args:
        pred: [N, A, C+1]
        target: [N, A]  (-1: ignore, 0: background, [1,C]: classes)
        reduction: 'sum', 'mean', 'none'
    Returns:
        reduced loss 
    """
    alpha = 0.25
    gamma = 2.0
    num_classes = pred.size(-1)
    pred = pred.view(-1, num_classes)
    target = target.view(-1)
    r = torch.arange(pred.size(0))
    ce = F.log_softmax(pred, dim=-1)[r, target.clamp_(0)]
    pt = torch.exp(ce)
    weights = (1 - pt).pow(gamma)

    # alpha version
    # p = y > 0
    # weights = (alpha * p + (1 - alpha) * (1 - p)) * weights.pow(gamma)

    loss = -(weights * ce)
    loss[target < 0] = 0
    return reduce(loss, reduction)

def adaptive_softmax_focal_loss(pred, target, reduction='none'):
    """
    Adaptive Softmax Focal Loss

    Args:
        pred: [N, A, C+1] — 分类预测
        target: [N, A] — 标签 (-1: ignore, 0: background, [1,C]: foreground classes)
        reduction: 'sum', 'mean', 'none'
    Returns:
        Reduced loss tensor
    """
    alpha = 0.25
    gamma_base = 1.0   # 最小gamma（自信预测时）
    gamma_range = 3.0  # gamma最大增幅，最大可达 gamma_base + gamma_range = 4.0

    num_classes = pred.size(-1)
    pred = pred.view(-1, num_classes)
    target = target.view(-1)
    r = torch.arange(pred.size(0), device=pred.device)

    # log softmax 取出预测目标类别的概率
    ce = F.log_softmax(pred, dim=-1)[r, target.clamp(min=0)]
    pt = torch.exp(ce)  # softmax 概率（正确类别的置信度）

    # 自适应 gamma（低置信度时 gamma 高，更聚焦难样本）
    adaptive_gamma = gamma_base + (1 - pt) * gamma_range

    # focal loss 的权重项
    weights = (1 - pt).pow(adaptive_gamma)

    # 加入 alpha（可选）：这里未引入 p=正负样本判定来调alpha，可以根据需要启用
    # alpha_t = alpha * (target > 0).float() + (1 - alpha) * (target == 0).float()
    # weights *= alpha_t

    # focal 损失
    loss = -(weights * ce)

    # 忽略 -1 的标签位置
    loss[target < 0] = 0

    return reduce(loss, reduction)

def smooth_l1_loss(pred, target, beta=0.11, reduction='sum'):
    """ smooth l1 loss

    Args:
        pred: positive anchors predictions [N, 4]
        target: positive anchors targets   [N, 4]
        beta: limit between l2 and l1 behavior
    """
    x = (pred - target).abs()
    l1 = x - 0.5 * beta
    l2 = (0.5 * x ** 2 / beta).to(l1)
    reg_loss = torch.where(x >= beta, l1, l2)
    return reduce(reg_loss, reduction)

def adaptive_smooth_l1_loss(pred, target, reduction='sum'):
    """ smooth l1 loss

    Args:
        pred: positive anchors predictions [N, 4]
        target: positive anchors targets   [N, 4]
        beta: limit between l2 and l1 behavior
    """
    x = (pred - target).abs()
    # 动态 beta：越靠近训练前期，beta 越大（对 outlier 更宽容）先宽松后严格
    # 这里用均值控制 beta 值
    beta = torch.clamp(x.mean() * 0.5, min=1e-2, max=0.21)
    l1 = x - 0.5 * beta
    l2 = (0.5 * x ** 2 / beta).to(l1)
    reg_loss = torch.where(x >= beta, l1, l2)
    return reduce(reg_loss, reduction)



class DetectionLoss(nn.Module):
    """Loss for Detection following SSD.

    This class returns 2 losses: 
    - one for anchor classification 
    - one for anchor refinement.

    Args:
        cls_loss_func (str): classification type loss
    """

    def __init__(self, cls_loss_func='softmax_focal_loss'):
        super(DetectionLoss, self).__init__()
        # 原本的：
        self.cls_loss_func = globals()[cls_loss_func]
        self.reg_loss_func = smooth_l1_loss

        # #自己尝试的两个优化版本：
        # self.cls_loss_func = adaptive_softmax_focal_loss
        # self.reg_loss_func = adaptive_smooth_l1_loss

    def forward(self, loc_preds, loc_targets, cls_preds, cls_targets):
        pos = cls_targets > 0
        num_pos = max(1, pos.sum().item())
        cls_loss = self.cls_loss_func(cls_preds, cls_targets, 'sum') / num_pos #类别的平均损失

        mask = pos.unsqueeze(2).expand_as(loc_preds)  # [N,#anchors,4]
        loc_loss = self.reg_loss_func(loc_preds[mask], loc_targets[mask].to(loc_preds), reduction='sum') / num_pos #这里的索引会自动展平相关tensor, mask->[N*A,], loc_preds->[N*A,4],然后索引
        return {"loc_loss": loc_loss, "cls_loss": cls_loss}
